import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Clear',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24}>
      <Stack gap={24}>
        <Stack gap={4}>
          <Heading level={3}>{city}</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        <Box paddingY={8}>
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {temperature}°{unit}
          </Text>
        </Box>

        <Stack direction="horizontal" justify="between">
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
            <Text weight="medium">{humidity}%</Text>
          </Stack>
          <Stack gap={4} align="end">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
            <Text weight="medium">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider />

        <Stack direction="horizontal" justify="between">
          {forecast.map((f, i) => (
            <Box 
              key={i} 
              padding={8} 
              borderRadius="var(--ggui-shape-radius-md, 8px)" 
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            >
              <Stack align="center" gap={4}>
                <Text variant="overline">{f.day ?? '-'}</Text>
                <Text size="xl">{f.icon ?? '☀️'}</Text>
                <Text variant="caption" weight="medium">
                  {f.high ?? 0}° / {f.low ?? 0}°
                </Text>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Text,
  Heading,
  Progress,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: Record<string, any>) => void;
}

export default function GeneratedComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });

  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('ggui:agent-data received', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = () => {
    if (currentStep === 1) {
      return formData.name.trim() !== '' && validateEmail(formData.email);
    }
    if (currentStep === 2) {
      return formData.satisfaction !== '';
    }
    return true;
  };

  const updateFormData = (field: keyof typeof formData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = () => {
    setIsSubmitting(true);
    props.onSubmit?.(formData);
    setTimeout(() => setIsSubmitting(false), 1000);
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {Math.min(currentStep, 5)} of 5
          </Text>
          <Progress
            value={((Math.min(currentStep, 5) - 1) / 4) * 100}
            max={100}
            variant="default"
            size="md"
            showLabel
          />
        </Box>

        <Card padding="var(--ggui-spacing-6, 24px)" radius="lg" border={true} shadow="md">
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Personal Details</Heading>
              <Input
                label="Name"
                value={formData.name}
                onChange={(v) => updateFormData('name', v)}
                required
              />
              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={(v) => updateFormData('email', v)}
                required
                error={formData.email && !validateEmail(formData.email) ? "Invalid email format" : undefined}
              />
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={formData.satisfaction}
                onChange={(val) => updateFormData('satisfaction', val)}
                options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))}
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>Feature Interests</Heading>
              {props.featureOptions.map((option) => (
                <Checkbox
                  key={option}
                  label={option}
                  checked={formData.features.includes(option)}
                  onChange={(checked) => {
                    const newFeatures = checked
                      ? [...formData.features, option]
                      : formData.features.filter((f) => f !== option);
                    updateFormData('features', newFeatures);
                  }}
                />
              ))}
            </Stack>
          )}

          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                value={formData.comments}
                onChange={(v) => updateFormData('comments', v)}
                maxLength={500}
                showCount
              />
            </Stack>
          )}

          {currentStep === 5 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Review Your Answers</Heading>
              <Divider />
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Text><strong>Name:</strong> {formData.name}</Text>
                <Text><strong>Email:</strong> {formData.email}</Text>
                <Text><strong>Satisfaction:</strong> {props.satisfactionLabels[parseInt(formData.satisfaction) - 1] || 'Not provided'}</Text>
                <Text><strong>Features:</strong> {formData.features.join(', ') || 'None'}</Text>
                <Text><strong>Comments:</strong> {formData.comments || 'None'}</Text>
              </Stack>
            </Stack>
          )}
        </Card>

        <Stack direction="horizontal" justify="between" gap="var(--ggui-spacing-4, 16px)">
          <Button
            variant="secondary"
            onClick={() => setCurrentStep((s) => Math.max(1, s - 1))}
            disabled={currentStep === 1 || isSubmitting}
          >
            Back
          </Button>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={() => setCurrentStep((s) => s + 1)}
              disabled={!isStepValid()}
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Box,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: {
    action: 'move' | 'edit' | 'create';
    taskId: string;
    data: any;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasks, setTasks] = useState(props.tasks ?? []);
  const [columns] = useState(props.columns ?? []);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) setTasks(event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleUpdate = (action: 'move' | 'edit' | 'create', taskId: string, data: any) => {
    setLoading(true);
    let updatedTasks = [...tasks];

    if (action === 'move') {
      updatedTasks = updatedTasks.map((t) => (t.id === taskId ? { ...t, column: data.column } : t));
    } else if (action === 'edit') {
      updatedTasks = updatedTasks.map((t) => (t.id === taskId ? { ...t, ...data } : t));
    } else if (action === 'create') {
      const newTask = { id: Date.now().toString(), ...data };
      updatedTasks.push(newTask);
    }

    setTasks(updatedTasks);
    props.onTaskUpdate?.({ action, taskId, data });
    setLoading(false);
  };

  const addTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    handleUpdate('create', '', { title: newTaskTitle, priority: newTaskPriority, column: columnId });
    setNewTaskTitle('');
    setIsAdding(null);
  };

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      default: return 'success';
    }
  };

  const doneColumnId = columns.find((c) => c.name?.toLowerCase() === 'done')?.id;
  const completedCount = tasks.filter((t) => t.column === doneColumnId).length;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Box 
          padding="var(--ggui-spacing-4, 16px)" 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          borderRadius="var(--ggui-shape-radius-md, 8px)"
        >
          <Heading level={2}>Project Board</Heading>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {completedCount} / {tasks.length} tasks completed
          </Text>
        </Box>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap align="start">
          {columns.map((col) => (
            <Box
              key={col.id}
              style={{ flex: 1, minWidth: '300px' }}
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              padding="var(--ggui-spacing-4, 16px)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
            >
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Heading level={4}>{col.name ?? 'Column'}</Heading>
                <Divider margin="var(--ggui-spacing-2, 8px)" />
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  {tasks
                    .filter((t) => t.column === col.id)
                    .map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3, 12px)" radius="md" shadow="sm">
                        <Stack gap="var(--ggui-spacing-2, 8px)">
                          <Text weight="semibold">{task.title ?? 'Untitled'}</Text>
                          <Stack direction="horizontal" justify="between" align="center">
                            <Badge variant={getPriorityVariant(task.priority) as any}>
                              {task.priority ?? 'low'}
                            </Badge>
                            <Avatar name={task.assignee ?? '??'} size={24} />
                          </Stack>
                          <Select
                            label="Move Task"
                            value={task.column ?? ''}
                            onChange={(val) => handleUpdate('move', task.id ?? '', { column: val })}
                            options={columns.map((c) => ({ value: c.id ?? '', label: c.name ?? '' }))}
                          />
                        </Stack>
                      </Card>
                    ))}
                </Stack>

                {isAdding === col.id ? (
                  <Card padding="var(--ggui-spacing-3, 12px)" radius="md">
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                      <Select
                        label="Priority"
                        value={newTaskPriority}
                        onChange={(val) => setNewTaskPriority(val as any)}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                        <Button size="sm" onClick={() => addTask(col.id ?? '')} disabled={loading}>
                          Add
                        </Button>
                        <Button size="sm" variant="ghost" onClick={() => setIsAdding(null)}>
                          Cancel
                        </Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setIsAdding(col.id ?? null)}>
                    + Add Task
                  </Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Box,
  Text,
  Heading,
  Input,
  Stack,
  Card,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
  'noble-gas': 'var(--ggui-color-info-200, #a5f3fc)',
  'alkali-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'alkaline-earth-metal': 'var(--ggui-color-success-200, #bbf7d0)',
  'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition-metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  'metalloid': 'var(--ggui-color-info-100, #cffafe)',
  'halogen': 'var(--ggui-color-error-100, #fee2e2)',
  'lanthanide': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  'actinide': 'var(--ggui-color-outlineVariant, #e4e4e7)',
};

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        (el.name?.toLowerCase() ?? '').includes(q) ||
        (el.symbol?.toLowerCase() ?? '').includes(q)
    );
  }, [props.elements, searchQuery]);

  const uniqueCategories = Array.from(new Set(props.elements.map((e) => e.category || 'unknown')));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Heading level={1}>Periodic Table</Heading>

        <Input
          label="Search Elements"
          placeholder="Search by name or symbol..."
          value={searchQuery}
          onChange={(val) => setSearchQuery(val)}
        />

        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-md, 8px)"
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
            {uniqueCategories.map((cat) => (
              <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                <Box
                  style={{ width: '16px', height: '16px' }}
                  borderRadius="var(--ggui-shape-radius-sm, 4px)"
                  background={CATEGORY_COLORS[cat] ?? 'var(--ggui-color-outline, #d4d4d8)'}
                />
                <Text variant="overline">{cat.replace('-', ' ')}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
          }}
        >
          {filteredElements.map((el) => (
            <Box
              key={el.atomicNumber ?? Math.random()}
              onClick={() => setSelectedElement(el)}
              onKeyDown={(e: React.KeyboardEvent) => {
                if (e.key === 'Enter' || e.key === ' ') setSelectedElement(el);
              }}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                cursor: 'pointer',
                transition: 'all 200ms ease',
                aspectRatio: '1',
                display: 'flex',
                flexDirection: 'column',
                padding: 'var(--ggui-spacing-1, 4px)',
                border: '1px solid transparent',
              }}
              background={CATEGORY_COLORS[el.category ?? ''] ?? 'var(--ggui-color-outlineVariant, #e4e4e7)'}
              borderRadius="var(--ggui-shape-radius-sm, 4px)"
            >
              <Text size="xs" weight="bold">{el.atomicNumber}</Text>
              <Box style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%' }}>
                <Text size="xl" weight="semibold">{el.symbol}</Text>
              </Box>
            </Box>
          ))}
        </Box>

        <Divider margin="var(--ggui-spacing-4, 16px)" />

        <Card shadow="md" padding="var(--ggui-spacing-6, 24px)">
          {selectedElement ? (
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text>Symbol: {selectedElement.symbol}</Text>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="bodySmall">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="label">Category: {selectedElement.category}</Text>
            </Stack>
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element from the grid to view detailed information.
            </Text>
          )}
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Box, Divider, Text, Heading, Input, Button, Badge } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending messages */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [localMessages, setLocalMessages] = useState<Message[]>(props.messages ?? []);
  const [inputText, setInputText] = useState('');
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail as Message;
      if (detail) {
        setLocalMessages((prev) => [...prev, detail]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [localMessages]);

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;

    const timestamp = new Date().toISOString();
    const payload = { text: trimmed, timestamp };

    setLocalMessages((prev) => [...prev, { sender: props.currentUser, ...payload }]);
    setInputText('');
    props.onSendMessage?.(payload);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    try {
      return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Card padding={0} border={true} radius="lg" style={{ height: '500px', display: 'flex', flexDirection: 'column' }}>
      <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3}>{props.title}</Heading>
          {props.participantCount !== undefined && (
            <Badge variant="secondary">{props.participantCount} Participants</Badge>
          )}
        </Stack>
      </Box>

      <div
        ref={scrollContainerRef}
        style={{
          flex: 1,
          overflowY: 'auto',
          display: 'flex',
          flexDirection: 'column',
          padding: 'var(--ggui-spacing-4)'
        }}
        role="log"
        aria-live="polite"
      >
        <Stack gap={16} align="stretch">
          {localMessages.map((msg, i) => {
            const isOwn = msg.sender === props.currentUser;
            const prevMsg = localMessages[i - 1];
            const showSender = i === 0 || prevMsg?.sender !== msg.sender;

            return (
              <Stack key={i} align={isOwn ? 'end' : 'start'} gap={4}>
                {showSender && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {msg.sender ?? 'Unknown'}
                  </Text>
                )}
                <Box
                  paddingX={12}
                  paddingY={8}
                  borderRadius={12}
                  background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                >
                  <Text color={isOwn ? '#ffffff' : 'var(--ggui-color-onSurface)'}>
                    {msg.text}
                  </Text>
                </Box>
                <Text variant="overline" size="xs">{formatTime(msg.timestamp)}</Text>
              </Stack>
            );
          })}
        </Stack>
      </div>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" gap={8} align="end">
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder="Type a message..."
              value={inputText}
              onChange={setInputText}
              onKeyDown={handleKeyDown}
            />
          </div>
          <Button
            variant="primary"
            disabled={!inputText.trim()}
            onClick={handleSend}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Box,
  Heading,
  Text,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated);

  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail;
      if (data?.stocks && Array.isArray(data.stocks)) {
        setLiveStocks(data.stocks);
        setLastUpdated(new Date().toISOString());
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Box paddingY="var(--ggui-spacing-4, 16px)">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1}>Market Watch</Heading>
            {lastUpdated && (
              <Text
                variant="bodySmall"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
              </Text>
            )}
          </Stack>
        </Box>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
          role="main"
        >
          {liveStocks.map((stock, idx) => {
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const isPositive = change >= 0;
            const semanticColor = isPositive
              ? 'var(--ggui-color-success, #16a34a)'
              : 'var(--ggui-color-error, #dc2626)';

            return (
              <Card
                key={stock.symbol ?? idx}
                shadow="md"
                radius="lg"
                padding="var(--ggui-spacing-4, 16px)"
                aria-label={`Stock ${stock.symbol ?? 'N/A'}: $${price.toFixed(2)}`}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={3}>{stock.symbol ?? 'N/A'}</Heading>
                    <Text
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-live="polite"
                    >
                      ${price.toFixed(2)}
                    </Text>
                  </Stack>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {stock.name ?? 'Unknown Company'}
                  </Text>
                  <Box>
                    <Stack
                      direction="horizontal"
                      gap="var(--ggui-spacing-1, 4px)"
                      align="center"
                    >
                      <span
                        style={{
                          color: semanticColor,
                          display: 'inline-flex',
                          alignItems: 'center',
                          transition: 'color 200ms ease-in-out',
                        }}
                      >
                        <Text color={semanticColor} weight="medium">
                          {isPositive ? '+' : ''}
                          {change.toFixed(2)} ({changePercent.toFixed(2)}%)
                        </Text>
                        <Icon
                          name={isPositive ? 'chevron-up' : 'chevron-down'}
                          size={16}
                          color={semanticColor}
                        />
                      </span>
                    </Stack>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Divider,
  Spacer,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Button,
  Progress,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  useEffect(() => {
    const handleAgentData = (e: any) => {
      console.log('Received agent data:', e.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const update = (key: string, val: any) => setFormData((prev) => ({ ...prev, [key]: val }));

  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  const isStep1Valid = formData.name.trim() !== '' && isEmailValid;

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-8)" radius="lg">
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={2}>Onboarding</Heading>
            <Progress value={(step / 3) * 100} size="md" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Step {step} of 3
            </Text>
          </Stack>

          <Divider />

          <Box paddingY="var(--ggui-spacing-2)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={formData.name}
                  onChange={(v) => update('name', v)}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(v) => update('email', v)}
                  error={formData.email && !isEmailValid ? 'Invalid email format' : undefined}
                  required
                />
                <RadioGroup
                  label="Choose an avatar"
                  value={formData.avatar}
                  onChange={(v) => update('avatar', v)}
                  options={props.avatarOptions.map((opt) => ({ label: opt, value: opt }))}
                  direction="horizontal"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(v) => update('role', v)}
                  options={props.roleOptions.map((opt) => ({ label: opt, value: opt }))}
                />
                <Toggle
                  label="Enable Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(v) => update('emailNotifications', v)}
                />
                <RadioGroup
                  label="Theme Preference"
                  value={formData.theme}
                  onChange={(v) => update('theme', v)}
                  options={[
                    { label: 'Light', value: 'light' },
                    { label: 'Dark', value: 'dark' },
                  ]}
                  direction="horizontal"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review your information</Heading>
                <Stack gap="var(--ggui-spacing-2)">
                  {Object.entries(formData).map(([k, v]) => (
                    <Box key={k}>
                      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                        {k}
                      </Text>
                      <Text variant="body">{String(v)}</Text>
                    </Box>
                  ))}
                </Stack>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between">
            <Button
              variant="secondary"
              onClick={() => setStep((s) => Math.max(s - 1, 1))}
              disabled={step === 1}
            >
              Go Back
            </Button>
            {step < 3 ? (
              <Button
                onClick={() => setStep((s) => Math.min(s + 1, 3))}
                disabled={step === 1 && !isStep1Valid}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => props.onComplete(formData)}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
